&lt;p&gt;&lt;pre class=&#34;line-numbers language-bash&#34; data-language=&#34;bash&#34;&gt;&lt;div class=&#34;caption&#34;&gt;&lt;span&gt;命令行提示符 command:(&#34;[root@localhost] $&#34;:1,9-10)||&#34;[admin@remotehost] #&#34;:4-6)&lt;/span&gt;&lt;/div&gt;&lt;code class=&#34;language-bash&#34;&gt;pwd
